noteContentFormat:
{% set article_title = selector:#activity-name|first ?? title %}
{% set author_name = selector:#js_author_name_text|first ?? selector:meta[name="author"]?content %}
{% set account_name = selector:#js_name|first|replace:"/^\s+|\s+$/g":"" %}
{% set publish_time = selector:#publish_time|first %}
{% set ip_loc = selector:#js_ip_wording|first %}
{% set article_html = selectorHtml:#js_content|remove_html:"mp-common-profile"|remove_html:"mpvoice"|remove_html:"mpvideosnap"|remove_html:"mp-style-type"|replace:"/\s+src=\"data:[^\"]*\"/g":""|replace:"data-src=\"":"src=\"" %}
{% set article_markdown = article_html|markdown|replace:"&amp;":"&" %}
# {{article_title}}

> [!info] 微信公众号文章
> 作者: {{author_name}}
> 公众号: {{account_name}}
> 原文: [{{url}}]({{url}})
> 发布时间: {{publish_time}}
{% if ip_loc %}> 属地: {{ip_loc}}
{% endif %}
## 正文

{{article_markdown}}

{% if highlights %}
## 高亮

{{highlights|fragment_link:"回到原文"|join:"\n\n"}}
{% endif %}
